// // This module implements a 4-bit DRAM cell with a 4-bit data input, a read/write control signal, and an output for the stored data. The write operation stores the data when the control signal is low, and the read operation outputs the stored data when the control signal is high.
module dram_cell (
    input wire clk,
    input wire reset,
    input wire [3:0] data_in,
    input wire rw, // 1 for write, 0 for read
    output reg [3:0] data_out
);
    reg [3:0] memory;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            memory <= 4'b0000;
            data_out <= 4'b0000;
        end else if (rw) begin
            memory <= data_in; // Write operation
        end else begin
            data_out <= memory; // Read operation
        end
    end
endmodule
